mapper.select:
select b.id, b.title, b.first_picture, b.first_picture_asset_id, b.create_time, b.update_time, b.is_published, b.is_internal, b.is_recommend, b.is_appreciation, b.is_comment_enabled, b.is_top, c.id as category_id, c.category_name from blog as b left join category as c on b.category_id=c.id
b.deleted_at is null
and b.title like #{titlePattern}
and b.category_id=#{categoryId}

select b.id, b.title, b.first_picture, b.first_picture_asset_id, b.create_time, b.update_time, b.is_published, b.is_internal, b.is_recommend, b.is_appreciation, b.is_comment_enabled, b.is_top, b.user_id, c.id as category_id, c.category_name from blog as b left join category as c on b.category_id=c.id where b.user_id=#{userId} and b.deleted_at is null
and b.title like #{titlePattern}
and b.category_id=#{categoryId}


select b.id, b.title, b.first_picture, b.first_picture_asset_id, b.create_time, b.update_time,
b.deleted_at, b.is_published, b.is_internal, b.is_recommend, b.is_appreciation,
b.is_comment_enabled, b.is_top, b.user_id, u.username, u.nickname, u.avatar, u.role,
c.id as category_id, c.category_name
from blog as b
left join user as u on b.user_id=u.id
left join category as c on b.category_id=c.id
where b.deleted_at is not null and b.deleted_at > #{cutoff}

	and b.title like #{titlePattern}


	and b.category_id=#{categoryId}


select b.id, b.title, b.first_picture, b.first_picture_asset_id, b.create_time, b.update_time,
b.deleted_at, b.is_published, b.is_internal, b.is_recommend, b.is_appreciation,
b.is_comment_enabled, b.is_top, b.user_id,
c.id as category_id, c.category_name
from blog as b left join category as c on b.category_id=c.id
where b.user_id=#{userId} and b.deleted_at is not null and b.deleted_at > #{cutoff}

	and b.title like #{titlePattern}


	and b.category_id=#{categoryId}

select b.id, b.title, coalesce(nullif(trim(b.description), ''), nullif(trim(left(b.content, 280)), ''), '暂无简介') as description, b.create_time, b.first_picture, b.is_top, c.category_name from blog as b left join category as c on b.category_id=c.id where b.is_published=true and b.deleted_at is null
and b.is_internal=false
order by b.is_top desc, b.is_recommend desc, b.update_time desc, b.id desc limit #{limitNum}
